// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./ILizSwapERC20.sol";

// ============================================================================
// ILizSwapPair.sol — Task 2.1: Contract Interfaces
// Giải quyết: C4-Component (Pair/Pool boundary)
//   [UC-03] Swap, [UC-04] Add Liquidity, [UC-05] Remove Liquidity
//   [FR-01.3] Công thức x*y=k, [FR-02.4] Mint LP Token, [FR-03.2] Burn LP Token
// Interface lõi AMM Pool, kế thừa ERC20 chuẩn để phát hành LP Token.
// ============================================================================

interface ILizSwapPair is ILizSwapERC20 {
    // -------------------------------------------------------------------------
    // Events
    // -------------------------------------------------------------------------

    /// @notice Phát ra khi LP Token được mint (Add Liquidity thành công) [UC-04]
    /// @param sender   Địa chỉ gọi hàm mint (thường là Router)
    /// @param amount0  Số lượng token0 đã nạp vào Pool
    /// @param amount1  Số lượng token1 đã nạp vào Pool
    event Mint(address indexed sender, uint256 amount0, uint256 amount1);

    /// @notice Phát ra khi LP Token được burn (Remove Liquidity thành công) [UC-05]
    /// @param sender   Địa chỉ gọi hàm burn (thường là Router)
    /// @param amount0  Số lượng token0 rút về
    /// @param amount1  Số lượng token1 rút về
    /// @param to       Địa chỉ nhận token sau khi rút
    event Burn(address indexed sender, uint256 amount0, uint256 amount1, address indexed to);

    /// @notice Phát ra khi Swap được thực hiện thành công [UC-03]
    /// @param sender      Địa chỉ khởi tạo swap (thường là Router)
    /// @param amount0In   Số lượng token0 đưa vào Pool
    /// @param amount1In   Số lượng token1 đưa vào Pool
    /// @param amount0Out  Số lượng token0 Pool trả ra
    /// @param amount1Out  Số lượng token1 Pool trả ra
    /// @param to          Địa chỉ nhận token đầu ra
    event Swap(
        address indexed sender,
        uint256 amount0In,
        uint256 amount1In,
        uint256 amount0Out,
        uint256 amount1Out,
        address indexed to
    );

    /// @notice Phát ra sau mỗi lần reserve được đồng bộ hoặc thay đổi
    /// @param reserve0  Reserve mới của token0
    /// @param reserve1  Reserve mới của token1
    event Sync(uint112 reserve0, uint112 reserve1);

    // -------------------------------------------------------------------------
    // View functions — Metadata
    // -------------------------------------------------------------------------

    /// @notice Địa chỉ Factory đã deploy Pool này
    function factory() external view returns (address);

    /// @notice Địa chỉ token0 (sort nhỏ hơn trong cặp)
    function token0() external view returns (address);

    /// @notice Địa chỉ token1 (sort lớn hơn trong cặp)
    function token1() external view returns (address);

    // -------------------------------------------------------------------------
    // View functions — AMM State [FR-01.3]
    // -------------------------------------------------------------------------

    /// @notice Đọc reserve hiện tại của cả hai token trong Pool
    /// @dev    Sử dụng để tính toán quote và getAmountOut theo công thức x*y=k [FR-01.3]
    /// @return reserve0           Reserve token0 (uint112 để tiết kiệm storage)
    /// @return reserve1           Reserve token1 (uint112)
    /// @return blockTimestampLast Block timestamp lần cập nhật reserve gần nhất
    function getReserves()
        external
        view
        returns (uint112 reserve0, uint112 reserve1, uint32 blockTimestampLast);

    // -------------------------------------------------------------------------
    // Mutating functions — Core AMM
    // -------------------------------------------------------------------------

    /// @notice Mint LP Token cho người cung cấp thanh khoản [UC-04] [FR-02.4]
    /// @dev    Caller (Router) phải chuyển token vào Pool trước khi gọi hàm này
    /// @param to  Địa chỉ nhận LP Token
    /// @return liquidity Số lượng LP Token được mint
    function mint(address to) external returns (uint256 liquidity);

    /// @notice Burn LP Token để rút thanh khoản về [UC-05] [FR-03.2]
    /// @dev    Caller (Router) phải chuyển LP Token vào Pool trước khi gọi
    /// @param to  Địa chỉ nhận token A và token B sau khi burn
    /// @return amount0 Số lượng token0 trả về
    /// @return amount1 Số lượng token1 trả về
    function burn(address to) external returns (uint256 amount0, uint256 amount1);

    /// @notice Thực hiện hoán đổi token theo công thức x*y=k [UC-03] [FR-01.3]
    /// @dev    Chính xác một trong hai (amount0Out, amount1Out) phải > 0
    ///         Caller phải đảm bảo invariant x*y=k vẫn thoả sau swap (tính phí 0.3%)
    /// @param amount0Out  Số lượng token0 muốn nhận ra
    /// @param amount1Out  Số lượng token1 muốn nhận ra
    /// @param to          Địa chỉ nhận token đầu ra
    /// @param data        Dữ liệu tuỳ chọn cho flash swap callback (truyền rỗng nếu không dùng)
    function swap(
        uint256 amount0Out,
        uint256 amount1Out,
        address to,
        bytes calldata data
    ) external;

    /// @notice Đồng bộ reserve với số dư token thực tế trong contract
    /// @dev    Hữu ích khi ai đó gửi token trực tiếp vào Pool (không qua Router)
    function sync() external;
}

project/contracts/interfaces/ILizSwapRou.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

// ============================================================================
// ILizSwapRouter.sol — Task 2.1: Contract Interfaces
// Giải quyết: C4-Component (Router boundary — lớp ngoại vi)
//   [UC-03] Swap, [UC-04] Add Liquidity, [UC-05] Remove Liquidity
//   [FR-01.3] Tính toán AmountOut (x*y=k), [FR-01.4] getAmountsOut (Price Impact)
//   [FR-01.5] swapExactTokensForTokens, [FR-02.2] quote, [FR-02.4] addLiquidity
//   [FR-03.2] removeLiquidity
// Router là điểm vào duy nhất của người dùng và Frontend [UC-03..05].
// ============================================================================

interface ILizSwapRouter {
    // -------------------------------------------------------------------------
    // View functions — Metadata
    // -------------------------------------------------------------------------

    /// @notice Địa chỉ Factory đã deploy hệ thống này
    function factory() external view returns (address);

    /// @notice Địa chỉ Wrapped Native Token (WBNB trên BSC)
    /// @dev    Dự án MVP không hỗ trợ swap native BNB trực tiếp nhưng giữ
    ///         field này để compatible với chuẩn Uniswap V2 Router interface
    function WETH() external view returns (address);

    // -------------------------------------------------------------------------
    // Pure / View functions — Tính toán AMM [FR-01.3] [FR-01.4] [FR-02.2]
    // -------------------------------------------------------------------------

    /// @notice Tính lượng tokenB tương đương với lượng tokenA theo tỷ giá Pool [FR-02.2]
    /// @dev    Công thức: amountB = amountA * reserveB / reserveA
    ///         Dùng khi người dùng nhập số lượng Token A để tự động điền Token B (Add Liquidity)
    /// @param amountA   Số lượng token A muốn cung cấp
    /// @param reserveA  Reserve hiện tại của token A trong Pool
    /// @param reserveB  Reserve hiện tại của token B trong Pool
    /// @return amountB  Số lượng token B tương đương cần cung cấp
    function quote(
        uint256 amountA,
        uint256 reserveA,
        uint256 reserveB
    ) external pure returns (uint256 amountB);

    /// @notice Tính số lượng token đầu ra sau phí 0.3% cho một swap cụ thể [FR-01.3]
    /// @dev    Công thức AMM có phí: amountOut = (amountIn * 997 * reserveOut) /
    ///                                            (reserveIn * 1000 + amountIn * 997)
    /// @param amountIn   Số lượng token đưa vào
    /// @param reserveIn  Reserve của token đưa vào
    /// @param reserveOut Reserve của token nhận ra
    /// @return amountOut Số lượng token nhận được sau phí
    function getAmountOut(
        uint256 amountIn,
        uint256 reserveIn,
        uint256 reserveOut
    ) external pure returns (uint256 amountOut);

    /// @notice Tính mảng số lượng token cho toàn bộ path swap [FR-01.4]
    /// @dev    Dùng để hiển thị Price Impact và Minimum Received trên UI
    /// @param amountIn Số lượng token đầu vào
    /// @param path     Mảng địa chỉ token theo thứ tự swap (e.g. [tokenA, tokenB])
    /// @return amounts Mảng số lượng token tại mỗi bước (amounts[0] = amountIn)
    function getAmountsOut(
        uint256 amountIn,
        address[] calldata path
    ) external view returns (uint256[] memory amounts);

    // -------------------------------------------------------------------------
    // Mutating functions — Liquidity Management [UC-04] [UC-05]
    // -------------------------------------------------------------------------

    /// @notice Thêm thanh khoản vào Pool tokenA/tokenB [UC-04] [FR-02.4]
    /// @dev    Tự động tạo Pool mới nếu chưa tồn tại (qua Factory.createPair)
    ///         Caller phải approve đủ allowance cho Router trước khi gọi [UC-02]
    ///         Revert nếu block.timestamp > deadline
    /// @param tokenA         Địa chỉ token A
    /// @param tokenB         Địa chỉ token B
    /// @param amountADesired Mong muốn nạp tối đa token A
    /// @param amountBDesired Mong muốn nạp tối đa token B
    /// @param amountAMin     Số lượng token A tối thiểu chấp nhận (chống slippage)
    /// @param amountBMin     Số lượng token B tối thiểu chấp nhận (chống slippage)
    /// @param to             Địa chỉ nhận LP Token
    /// @param deadline       Unix timestamp — revert nếu quá hạn
    /// @return amountA    Số lượng token A thực sự nạp vào
    /// @return amountB    Số lượng token B thực sự nạp vào
    /// @return liquidity  Số lượng LP Token được mint cho `to`
    function addLiquidity(
        address tokenA,
        address tokenB,
        uint256 amountADesired,
        uint256 amountBDesired,
        uint256 amountAMin,
        uint256 amountBMin,
        address to,
        uint256 deadline
    ) external returns (uint256 amountA, uint256 amountB, uint256 liquidity);

    /// @notice Rút thanh khoản từ Pool tokenA/tokenB [UC-05] [FR-03.2]
    /// @dev    Caller phải approve LP Token cho Router trước khi gọi [UC-02] [FR-03.3]
    ///         Revert nếu block.timestamp > deadline
    /// @param tokenA     Địa chỉ token A
    /// @param tokenB     Địa chỉ token B
    /// @param liquidity  Số lượng LP Token muốn đốt (burn)
    /// @param amountAMin Số lượng token A tối thiểu nhận về (chống slippage)
    /// @param amountBMin Số lượng token B tối thiểu nhận về (chống slippage)
    /// @param to         Địa chỉ nhận token A và B sau khi rút
    /// @param deadline   Unix timestamp — revert nếu quá hạn
    /// @return amountA   Số lượng token A thực sự nhận về
    /// @return amountB   Số lượng token B thực sự nhận về
    function removeLiquidity(
        address tokenA,
        address tokenB,
        uint256 liquidity,
        uint256 amountAMin,
        uint256 amountBMin,
        address to,
        uint256 deadline
    ) external returns (uint256 amountA, uint256 amountB);

    // -------------------------------------------------------------------------
    // Mutating functions — Swap [UC-03] [FR-01.5]
    // -------------------------------------------------------------------------

    /// @notice Swap chính xác số lượng token đầu vào, nhận tối thiểu amountOutMin [UC-03] [FR-01.5]
    /// @dev    Duyệt qua toàn bộ path, thực hiện swap theo từng bước
    ///         Caller phải approve token đầu tiên trong path cho Router [UC-02]
    ///         Revert nếu amountOut < amountOutMin (slippage protection) hoặc deadline hết hạn
    /// @param amountIn     Số lượng token đầu vào chính xác
    /// @param amountOutMin Số lượng token đầu ra tối thiểu chấp nhận
    /// @param path         Mảng địa chỉ token theo thứ tự swap (ít nhất 2 phần tử)
    /// @param to           Địa chỉ nhận token đầu ra cuối cùng
    /// @param deadline     Unix timestamp — revert nếu quá hạn
    /// @return amounts     Mảng số lượng token tại mỗi bước của path
    function swapExactTokensForTokens(
        uint256 amountIn,
        uint256 amountOutMin,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external returns (uint256[] memory amounts);
}

project/contracts/periphery/libraries/Li.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

// ============================================================================
// LizSwapLibrary.sol — Task 2.5: Math Libraries
// Giải quyết:
//   [FR-01.3] Công thức tính toán AMM có phí 0.3% (getAmountOut)
//   [FR-01.4] Tính output multi-hop (getAmountsOut) — phục vụ Price Impact
//   [FR-02.2] Auto-quote số lượng Token B theo tỷ giá Pool (quote)
//   project-structure.md §1 — contracts/periphery/libraries/
//
// Thư viện ngoại vi cung cấp các hàm tính toán phức hợp cho Router,
// bao gồm: sortTokens, pairFor, getReserves, quote, getAmountOut,
// getAmountsOut. Router sẽ import và gọi trực tiếp thư viện này.
// ============================================================================

import "../../interfaces/ILizSwapFactory.sol";
import "../../interfaces/ILizSwapPair.sol";
import "./Math.sol";

/**
 * @title LizSwapLibrary
 * @notice Thư viện tính toán phụ trợ cho LizSwapRouter.
 *         Cung cấp các hàm tiện ích để tính toán quote, output amount,
 *         và tra cứu reserves từ Factory/Pair contract.
 *
 * @dev Tất cả hàm đều là `internal` — chỉ được gọi nội bộ từ Router.
 *      Không deploy riêng (Solidity library không có address riêng).
 *
 *      Các hàm được phân loại:
 *      ┌─────────────────────────────────────────────────────────────┐
 *      │ Pure functions (không truy cập state)                       │
 *      │   sortTokens  — sắp xếp token theo địa chỉ                 │
 *      │   quote        — tính amountB theo tỷ giá Pool hiện tại     │
 *      │   getAmountOut — tính output với phí 0.3% (x*y=k formula)  │
 *      ├─────────────────────────────────────────────────────────────┤
 *      │ View functions (đọc state từ contract bên ngoài)            │
 *      │   pairFor      — lấy địa chỉ Pair từ Factory               │
 *      │   getReserves  — lấy reserves đã sort theo input order      │
 *      │   getAmountsOut — tính output cho multi-hop path            │
 *      └─────────────────────────────────────────────────────────────┘
 *
 *      Khác với Uniswap V2 gốc (dùng CREATE2 để tính pairFor offline):
 *      - pairFor() gọi trực tiếp ILizSwapFactory.getPair() (đơn giản hơn,
 *        phù hợp mục tiêu học thuật, không cần tính init code hash)
 */
library LizSwapLibrary {
    // =========================================================================
    // Hàm sortTokens — Sắp xếp cặp token theo canonical order
    // =========================================================================

    /**
     * @notice Sắp xếp hai địa chỉ token theo thứ tự tăng dần (canonical order).
     * @dev Uniswap V2 quy ước: token0 < token1 khi so sánh địa chỉ dạng uint160.
     *      Canonical order này đảm bảo một cặp (A, B) và (B, A) luôn map
     *      tới cùng một Pair contract — tránh tạo duplicate pools.
     *
     *      Validation: tokenA != tokenB (không thể tạo pool với cùng token)
     *                  Cả hai address != address(0)
     *
     * @param tokenA Địa chỉ token A (thứ tự bất kỳ)
     * @param tokenB Địa chỉ token B (thứ tự bất kỳ)
     * @return token0 Địa chỉ nhỏ hơn (sort đầu tiên)
     * @return token1 Địa chỉ lớn hơn (sort thứ hai)
     */
    function sortTokens(
        address tokenA,
        address tokenB
    ) internal pure returns (address token0, address token1) {
        require(tokenA != tokenB, "LizSwapLibrary: IDENTICAL_ADDRESSES");
        (token0, token1) = tokenA < tokenB
            ? (tokenA, tokenB)
            : (tokenB, tokenA);
        require(token0 != address(0), "LizSwapLibrary: ZERO_ADDRESS");
    }

    // =========================================================================
    // Hàm pairFor — Tra cứu địa chỉ Pair từ Factory
    // =========================================================================

    /**
     * @notice Lấy địa chỉ Pair contract từ Factory registry.
     * @dev [C4-Component - Router: "Lấy địa chỉ Pool (getPair)"]
     *      Gọi ILizSwapFactory.getPair() thay vì tính offline bằng CREATE2
     *      (phù hợp cho dự án học thuật — đơn giản hơn, dễ hiểu hơn).
     *
     *      Revert nếu chưa tồn tại Pool cho cặp token này.
     *
     * @param factory Địa chỉ LizSwapFactory contract
     * @param tokenA  Địa chỉ token A (thứ tự bất kỳ)
     * @param tokenB  Địa chỉ token B (thứ tự bất kỳ)
     * @return pair   Địa chỉ LizSwapPair contract tương ứng
     */
    function pairFor(
        address factory,
        address tokenA,
        address tokenB
    ) internal view returns (address pair) {
        pair = ILizSwapFactory(factory).getPair(tokenA, tokenB);
        require(pair != address(0), "LizSwapLibrary: PAIR_NOT_EXISTS");
    }

    // =========================================================================
    // Hàm getReserves — Lấy reserves đã sort đúng thứ tự input
    // =========================================================================

    /**
     * @notice Lấy reserves của Pool và sắp xếp theo thứ tự tokenA/tokenB.
     * @dev [FR-01.3] Đảm bảo reserveA luôn tương ứng với tokenA (dù thứ tự
     *      trong Pool có thể là token0/token1 khác với input).
     *
     *      Quy trình:
     *      1. sortTokens() → xác định token0 (canonical)
     *      2. Gọi ILizSwapPair.getReserves() → lấy reserve0, reserve1
     *      3. Nếu tokenA == token0: reserveA = reserve0, reserveB = reserve1
     *         Ngược lại:            reserveA = reserve1, reserveB = reserve0
     *
     *      Validation: Pool phải tồn tại (pairFor) và đã có thanh khoản.
     *
     * @param factory Địa chỉ LizSwapFactory contract
     * @param tokenA  Địa chỉ token A (thứ tự bất kỳ — caller xác định)
     * @param tokenB  Địa chỉ token B
     * @return reserveA Reserve của tokenA trong Pool
     * @return reserveB Reserve của tokenB trong Pool
     */
    function getReserves(
        address factory,
        address tokenA,
        address tokenB
    ) internal view returns (uint256 reserveA, uint256 reserveB) {
        // Xác định token0 để biết thứ tự reserve trong Pair
        (address token0, ) = sortTokens(tokenA, tokenB);

        // Lấy địa chỉ Pair và đọc reserves
        address pair = pairFor(factory, tokenA, tokenB);
        (uint112 reserve0, uint112 reserve1, ) = ILizSwapPair(pair).getReserves();

        // Map về đúng thứ tự tokenA/tokenB (không phải token0/token1)
        (reserveA, reserveB) = tokenA == token0
            ? (uint256(reserve0), uint256(reserve1))
            : (uint256(reserve1), uint256(reserve0));

        // Validate Pool đã có thanh khoản
        require(
            reserveA > 0 && reserveB > 0,
            "LizSwapLibrary: INSUFFICIENT_LIQUIDITY"
        );
    }

    // =========================================================================
    // Hàm quote — Tính amountB proportional theo reserves
    // =========================================================================

    /**
     * @notice Tính số lượng tokenB tương đương với amountA theo tỷ giá Pool hiện tại.
     * @dev [FR-02.2] Dùng khi thêm thanh khoản: người dùng nhập amountA,
     *      hệ thống tự động tính amountB cần nạp proportional.
     *
     *      Công thức: amountB = amountA * reserveB / reserveA
     *
     *      Đây là tính toán KHÔNG có phí (pure ratio) — chỉ dùng để quote,
     *      không dùng để tính output của swap.
     *
     *      Validation:
     *        amountA > 0  (phải có lượng đầu vào)
     *        reserveA > 0 và reserveB > 0 (Pool phải có thanh khoản)
     *
     * @param amountA  Số lượng tokenA muốn cung cấp
     * @param reserveA Reserve của tokenA hiện có trong Pool
     * @param reserveB Reserve của tokenB hiện có trong Pool
     * @return amountB Số lượng tokenB tương đương cần cung cấp thêm
     */
    function quote(
        uint256 amountA,
        uint256 reserveA,
        uint256 reserveB
    ) internal pure returns (uint256 amountB) {
        require(amountA > 0, "LizSwapLibrary: INSUFFICIENT_AMOUNT");
        require(
            reserveA > 0 && reserveB > 0,
            "LizSwapLibrary: INSUFFICIENT_LIQUIDITY"
        );
        // amountB = amountA * reserveB / reserveA (tỷ lệ giá hiện tại trong Pool)
        amountB = (amountA * reserveB) / reserveA;
    }

    // =========================================================================
    // Hàm getAmountOut — Tính output theo công thức x*y=k có phí 0.3%
    // =========================================================================

    /**
     * @notice Tính số lượng token đầu ra khi swap, có tính phí 0.3%.
     * @dev [FR-01.3] Công thức Constant Product Formula với fee:
     *
     *      Gọi:
     *        amountInWithFee = amountIn * 997           (sau phí 0.3%)
     *        numerator       = amountInWithFee * reserveOut
     *        denominator     = reserveIn * 1000 + amountInWithFee
     *        amountOut       = numerator / denominator
     *
     *      Phí 0.3% = 0.3/100 = 3/1000
     *      Vì Solidity không có float: nhân 1000 để tránh decimal:
     *        - amountIn hiệu quả = amountIn * 997 / 1000 (sau phí)
     *        - Đảm bảo invariant: (reserveIn + amountIn*997/1000) *
     *                              (reserveOut - amountOut) >= reserveIn * reserveOut
     *
     *      Phí 0.3% tự động tích luỹ trong Pool
     *      (không rút ra — LP holders hưởng lợi khi reserves tăng).
     *
     *      Validation:
     *        amountIn > 0
     *        reserveIn > 0 và reserveOut > 0
     *
     * @param amountIn  Số lượng token đầu vào (trước phí)
     * @param reserveIn Reserve của token đầu vào trong Pool
     * @param reserveOut Reserve của token đầu ra trong Pool
     * @return amountOut Số lượng token đầu ra (sau phí 0.3%)
     */
    function getAmountOut(
        uint256 amountIn,
        uint256 reserveIn,
        uint256 reserveOut
    ) internal pure returns (uint256 amountOut) {
        require(amountIn > 0, "LizSwapLibrary: INSUFFICIENT_INPUT_AMOUNT");
        require(
            reserveIn > 0 && reserveOut > 0,
            "LizSwapLibrary: INSUFFICIENT_LIQUIDITY"
        );

        // Áp dụng phí 0.3%: amountIn hiệu quả = amountIn * 997
        uint256 amountInWithFee = amountIn * 997;

        // numerator = amountInWithFee * reserveOut
        uint256 numerator = amountInWithFee * reserveOut;

        // denominator = reserveIn * 1000 + amountInWithFee
        // (reserveIn * 1000 đại diện cho "base" không có phí)
        uint256 denominator = reserveIn * 1000 + amountInWithFee;

        // amountOut = floor(numerator / denominator)
        amountOut = numerator / denominator;
    }

    // =========================================================================
    // Hàm getAmountsOut — Tính output cho multi-hop path
    // =========================================================================

    /**
     * @notice Tính mảng output amounts cho chuỗi hoán đổi multi-hop.
     * @dev [FR-01.4] Phục vụ hiển thị Price Impact và Minimum Received trên UI.
     *      Router dùng hàm này để tính lượng token nhận được ở từng bước.
     *
     *      Ví dụ path 2-hop: [TokenA, TokenB, TokenC]
     *        amounts[0] = amountIn (TokenA input)
     *        amounts[1] = getAmountOut(amountIn, reserveA_B, reserveB_A) → TokenB
     *        amounts[2] = getAmountOut(amounts[1], reserveB_C, reserveC_B) → TokenC
     *
     *      Mỗi bước áp dụng phí 0.3% (qua getAmountOut).
     *      Path phải có ít nhất 2 địa chỉ (1 hop tối thiểu).
     *
     *      Validation:
     *        path.length >= 2  (ít nhất 1 cặp token)
     *        amountIn > 0      (phải có lượng đầu vào)
     *
     * @param factory  Địa chỉ LizSwapFactory contract
     * @param amountIn Số lượng token đầu vào (path[0])
     * @param path     Mảng địa chỉ token định tuyến (path[0] → ... → path[n])
     * @return amounts Mảng amounts tại mỗi bước: amounts[0] = input, amounts[n] = final output
     */
    function getAmountsOut(
        address factory,
        uint256 amountIn,
        address[] memory path
    ) internal view returns (uint256[] memory amounts) {
        require(path.length >= 2, "LizSwapLibrary: INVALID_PATH");

        // Khởi tạo mảng kết quả với độ dài bằng path
        amounts = new uint256[](path.length);
        amounts[0] = amountIn;

        // Duyệt qua từng hop trong path
        for (uint256 i = 0; i < path.length - 1; i++) {
            // Lấy reserves cho cặp token tại hop hiện tại
            (uint256 reserveIn, uint256 reserveOut) = getReserves(
                factory,
                path[i],       // token đầu vào hop i
                path[i + 1]    // token đầu ra hop i
            );
            // Tính output của hop này → input của hop tiếp theo
            amounts[i + 1] = getAmountOut(amounts[i], reserveIn, reserveOut);
        }
    }
}

